// ═══════════════ ESTADO ═══════════════
let registros = [];
let clientes = [];
let facturas = [];
let config = { umbrales:{USD:0,CLP:0,EUR:0,BRL:0,ARS:0,PEN:0}, logo:LOGO_ALUN, autoDescarga:false, ultimoFolio:0, ultimoFolioCliente:0, ultimoFolioFactura:0, ultimoFolioCompra:0, ultimoFolioMov:0, ultimoFolioCuenta:0 };

let editandoId = null;
let editandoClienteId = null;
let clienteSeleccionadoId = null;
let tipoPersonaActual = 'natural';
let facturaModoActual = 'individual';
