// ═══════════════ ALERTAS DE MONTO ═══════════════
function calcularAlertas(){
  const mes=mesActual(); const delMes=registros.filter(r=>r.transferencia.fecha&&r.transferencia.fecha.startsWith(mes));
  const montos={}; delMes.forEach(r=>{ const m=r.transferencia.moneda||'???'; montos[m]=(montos[m]||0)+(r.transferencia.monto||0); });
  const al=[]; Object.entries(config.umbrales).forEach(([m,u])=>{ if(!u||u<=0) return; const ac=montos[m]||0; if(ac>u) al.push({tipo:'umbral',key:'umbral|'+m+'|'+mes,moneda:m,acumulado:ac,umbral:u,msg:'Acumulado '+fmtNum(ac)+' '+m+' supera el umbral de '+fmtNum(u)+' '+m+' ('+Math.round(ac/u*100)+'%)'}); });
  // Posible FRACCIONAMIENTO: mismo cliente y moneda, ventana de 30 días, 2+ operaciones
  // cada una bajo el umbral pero cuya suma lo supera (señal de estructuración).
  const hace30=new Date(Date.now()-30*24*3600*1000).toISOString().slice(0,10);
  const porCli={};
  registros.forEach(r=>{ const f=r.transferencia.fecha; if(!f||f<hace30) return; const m=r.transferencia.moneda||'???'; const u=config.umbrales[m]||0; if(u<=0) return; if((r.transferencia.monto||0)>=u) return; const k=(r.clienteId||'?')+'|'+m; (porCli[k]=porCli[k]||[]).push(r); });
  Object.entries(porCli).forEach(([k,ops])=>{ if(ops.length<2) return; const p=k.split('|'); const u=config.umbrales[p[1]]||0; const tot=ops.reduce((s,r)=>s+(r.transferencia.monto||0),0);
    if(tot>u) al.push({tipo:'fraccionamiento',key:'frac|'+k,clienteId:p[0],moneda:p[1],acumulado:tot,umbral:u,msg:ops.length+' operaciones de '+clienteNombre(p[0])+' en los últimos 30 días suman '+fmtNum(tot)+' '+p[1]+' — cada una bajo el umbral de '+fmtNum(u)+' '+p[1]+' (posible fraccionamiento).'}); });
  // Excluir alertas descartadas con justificación (quedan en el registro de auditoría).
  return al.filter(a=>!alertasDescartadas.some(d=>d.key===a.key));
}
// Descarte de alerta con justificación obligatoria (trazable para la UAF).
function descartarAlerta(key){
  const j=prompt('Justificación del descarte de esta alerta (obligatoria; queda registrada para auditoría):'); if(j===null) return;
  if(!j.trim()){ alert('Debe indicar una justificación.'); return; }
  alertasDescartadas.push({ id:'ad'+Date.now(), key:key, justificacion:j.trim(), usuario:usuarioActual(), fecha:new Date().toISOString() });
  guardarAlertasDescartadas(); verificarAlertas(); renderAlertas();
}
function verificarAlertas(){ const a=calcularAlertas(); const badge=document.getElementById('nav-alert-badge'); if(a.length){ if(badge)badge.style.display='inline'; } else { if(badge)badge.style.display='none'; } }
function renderAlertas(){
  const el=document.getElementById('alertas-content'); const mes=mesActual();
  const delMes=registros.filter(r=>r.transferencia.fecha&&r.transferencia.fecha.startsWith(mes));
  const montos={}; delMes.forEach(r=>{ const m=r.transferencia.moneda||'???'; montos[m]=(montos[m]||0)+(r.transferencia.monto||0); });
  const alertas=calcularAlertas(); let html='';
  if(!alertas.length) html+='<div class="card"><div class="empty-state"><i class="ti ti-circle-check" style="color:#639922;"></i><p>Sin alertas activas este mes.</p></div></div>';
  else alertas.forEach(a=>{ html+='<div class="alert-box alert-danger" style="margin-bottom:10px;display:flex;align-items:flex-start;gap:8px;"><i class="ti ti-alert-triangle"></i><div style="flex:1;"><strong>'+(a.tipo==='fraccionamiento'?'Posible fraccionamiento — '+a.moneda:'Alerta de umbral: '+a.moneda)+'</strong><br>'+a.msg+'</div><button class="btn btn-secondary btn-sm" onclick="descartarAlerta(\''+a.key+'\')" title="Descartar con justificación"><i class="ti ti-x"></i> Descartar</button></div>'; });
  if(alertasDescartadas.length){ html+='<div class="card" style="margin-bottom:10px;"><div class="card-title"><i class="ti ti-clipboard-off"></i> Alertas descartadas (registro de auditoría)</div>'+alertasDescartadas.slice(-10).reverse().map(d=>'<div style="font-size:12px;color:var(--text-muted);margin-bottom:8px;"><strong>'+esc(d.key)+'</strong> · '+(d.fecha||'').replace('T',' ').slice(0,16)+(d.usuario?' · '+esc(d.usuario):'')+'<br>Justificación: '+esc(d.justificacion)+'</div>').join('')+'</div>'; }
  html+='<div class="card"><div class="card-title"><i class="ti ti-chart-pie"></i> Resumen mensual por moneda — '+mes+'</div>';
  const ent=Object.entries(montos);
  if(!ent.length) html+='<p style="font-size:13px;color:var(--text-muted);">Sin operaciones este mes.</p>';
  else ent.forEach(([m,t])=>{ const u=config.umbrales[m]||0; const pct=u>0?Math.min(100,Math.round(t/u*100)):null; const col=pct!==null?(pct>=100?'#E24B4A':pct>=75?'#EF9F27':'#639922'):'#6E8169'; html+='<div style="margin-bottom:14px;"><div style="display:flex;justify-content:space-between;font-size:13px;margin-bottom:5px;"><span><strong>'+m+'</strong> — '+fmtNum(t)+' '+m+'</span><span style="color:var(--text-muted);">'+(u>0?'Umbral: '+fmtNum(u)+' '+m:'Sin umbral')+'</span></div>'+(u>0?'<div class="progress-bar-bg"><div class="progress-bar-fill" style="width:'+pct+'%;background:'+col+';"></div></div>':'')+'</div>'; });
  html+='</div>'; el.innerHTML=html;
}

// ═══════════════ CONFIG ═══════════════
function cargarConfigForm(){
  ['USD','CLP','EUR','BRL','ARS','PEN'].forEach(m=>{const e=document.getElementById('th-'+m); if(e)e.value=config.umbrales[m]||'';});
  if(config.logo){ const p=document.getElementById('logo-preview-config'); if(p) p.innerHTML='<img src="'+config.logo+'" style="max-height:60px;margin-top:8px;border-radius:var(--radius-sm);">'; }
  const at=document.getElementById('cfg-autodescarga'); if(at) at.checked=!!config.autoDescarga;
}
function guardarConfig(){
  ['USD','CLP','EUR','BRL','ARS','PEN'].forEach(m=>{ config.umbrales[m]=parseFloat(v('th-'+m))||0; });
  const at=document.getElementById('cfg-autodescarga'); if(at) config.autoDescarga=at.checked;
  guardarConfigData(); actualizarDashboard(); verificarAlertas(); alert('Configuración guardada.');
}

// ═══════════════ ZIP / NUBE ═══════════════
function dataURIaBase64(d){ const i=(d||'').indexOf(','); return i>=0?d.slice(i+1):(d||''); }
function descargarBlob(blob,nombre){ const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=nombre; document.body.appendChild(a); a.click(); a.remove(); setTimeout(()=>URL.revokeObjectURL(a.href),4000); }
function resumenOperacion(r){
  const c=clientePorId(r.clienteId)||{}; const info=estadoInfo(r); const L=[];
  L.push('OPERACIÓN '+folioDe(r)+'  ['+info.estado.toUpperCase()+' - '+info.texto+']');
  L.push('Inversiones Alun SpA — Regla del Viaje (UAF Circular 62)');
  L.push('Fecha de operación: '+(r.transferencia.fecha||''));
  L.push('Registrado: '+(r.creadoEn||'').replace('T',' ').slice(0,19));
  L.push(''); L.push('--- CLIENTE (ORDENANTE) ---');
  L.push('Folio cliente: '+(c.folio||'')); L.push('Nombre: '+(c.nombre||'')); L.push('RUT/Doc: '+(c.rut||''));
  L.push('Tipo: '+(c.tipoPersona==='juridica'?'Persona jurídica':'Persona natural'));
  L.push('Nacionalidad: '+(c.nacionalidad||'')); L.push('Dirección: '+[c.direccion,c.comuna,c.ciudad,c.pais].filter(Boolean).join(', '));
  L.push('Teléfono: '+(c.telefono||'')); L.push('Actividad/giro: '+(c.actividad||'')); L.push('Origen de fondos: '+(c.origenFondos||'')); L.push('PEP: '+(c.pep==='si'?'Sí':'No'));
  L.push(''); L.push('--- BENEFICIARIO ---');
  L.push('Nombre: '+(r.beneficiario.nombre||'')); L.push('Documento: '+(r.beneficiario.documento||'')); L.push('País: '+(r.beneficiario.pais||'')); L.push('Ciudad: '+(r.beneficiario.ciudad||'')); L.push('Banco: '+(r.beneficiario.banco||'')); L.push('N° cuenta: '+(r.beneficiario.cuenta||''));
  L.push(''); L.push('--- TRANSFERENCIA ---');
  L.push('Monto enviado: '+fmtNum(r.transferencia.monto,2)+' '+(r.transferencia.moneda||''));
  L.push('Monto recibido: '+(r.transferencia.montoDestino?fmtNum(r.transferencia.montoDestino,2)+' '+(r.transferencia.monedaDestino||''):'-'));
  L.push('Propósito: '+(r.transferencia.proposito||'')); L.push('Canal: '+(r.transferencia.canal||'')); L.push('Referencia: '+(r.transferencia.referencia||'')); L.push('Relación: '+(r.transferencia.relacion||'')); L.push('Observaciones: '+(r.transferencia.observaciones||''));
  const vl=r.verificacionListas||{}; L.push(''); L.push('--- VERIFICACIÓN EN LISTAS / BILLETERAS (revisión del destinatario) ---'); L.push('¿Requirió verificación?: '+(vl.requerida==='si'?'Sí':'No')); if(vl.requerida==='si'){ L.push('Resultado: '+(vl.resultado||'')); L.push('Comentario: '+(vl.comentario||'')); }
  L.push('Pago en efectivo (ROE): '+(r.pagoEfectivo==='si'?'Sí':'No'));
  L.push(''); L.push('--- DOCUMENTOS ---');
  L.push('Comprobante (hash/SWIFT): '+(comprobantePresente(r)?'SÍ':'PENDIENTE'));
  if(r.facturaModo==='agrupada'){ const g=facturaPorId(r.facturaGrupoId)||{}; L.push('Factura: AGRUPADA N° '+(g.numero||'')+' ('+(g.archivo&&g.archivo.data?'con documento':'PENDIENTE')+')'); }
  else L.push('Factura: '+(facturaPresente(r)?'SÍ (individual)':'PENDIENTE'));
  L.push('Otros adjuntos: '+((r.otros||[]).length));
  return L.join('\n');
}
function agregarOperacionAZip(zip,r){
  const carpeta=zip.folder(folioDe(r));
  carpeta.file('resumen.txt', resumenOperacion(r));
  carpeta.file('datos.json', JSON.stringify({transferencia:r, cliente:clientePorId(r.clienteId)||null, factura: r.facturaModo==='agrupada'?(facturaPorId(r.facturaGrupoId)||null):null}, null, 2));
  if(r.comprobante&&r.comprobante.data){ try{ carpeta.file('COMPROBANTE_'+r.comprobante.nombre, dataURIaBase64(r.comprobante.data), {base64:true}); }catch(e){} }
  let fac = r.facturaModo==='agrupada' ? (facturaPorId(r.facturaGrupoId)||{}).archivo : r.facturaIndividual;
  if(fac&&fac.data){ try{ carpeta.file('FACTURA_'+fac.nombre, dataURIaBase64(fac.data), {base64:true}); }catch(e){} }
  (r.otros||[]).forEach((f,i)=>{ if(f&&f.data){ try{ carpeta.file('ADJUNTO_'+(i+1)+'_'+f.nombre, dataURIaBase64(f.data), {base64:true}); }catch(e){} } });
}
async function descargarOperacion(id){
  if(typeof JSZip==='undefined'){ alert('Para crear la carpeta ZIP se necesita internet la primera vez. Reintente con conexión.'); return; }
  const r=registros.find(x=>x.id===id); if(!r) return;
  const zip=new JSZip(); agregarOperacionAZip(zip,r);
  const blob=await zip.generateAsync({type:'blob'}); descargarBlob(blob, folioDe(r)+'.zip');
}
async function descargarTodoZip(){
  if(typeof JSZip==='undefined'){ alert('Para crear el ZIP se necesita internet la primera vez. Reintente con conexión.'); return; }
  if(!registros.length){ alert('No hay operaciones para exportar.'); return; }
  const zip=new JSZip(); registros.forEach(r=>agregarOperacionAZip(zip,r));
  if(clientes.length){ const cz=zip.folder('CLIENTES'); clientes.forEach(c=>agregarDocsClienteAZip(cz.folder((c.folio||c.id)), c)); }
  const blob=await zip.generateAsync({type:'blob'}); descargarBlob(blob,'alun_respaldo_'+hoy()+'.zip');
}

// ═══════════════ EXPORT CSV / JSON / IMPORT ═══════════════
function exportCSV(){
  if(!registros.length){ alert('No hay registros.'); return; }
  let lista=registros; const desde=v('exp-desde'), hasta=v('exp-hasta');
  if(desde) lista=lista.filter(r=>r.transferencia.fecha>=desde);
  if(hasta) lista=lista.filter(r=>r.transferencia.fecha<=hasta);
  if(!lista.length){ alert('Sin registros en ese rango.'); return; }
  const cols=['Folio','Estado','Cliente folio','Cliente','RUT cliente','Fecha','Beneficiario','Doc. beneficiario','País destino','Banco','Cuenta','Monto','Moneda','Monto destino','Moneda destino','Referencia','Canal','Propósito','Relación','¿Verificación listas?','Resultado revisión destinatario','Comentario revisión','¿Pago efectivo (ROE)?','Equivalente USD','Incluye ROE (>=10k)','Estado ROS','Folio/justificación ROS','Comprobante','N° factura','Factura','N° otros adjuntos','Usuario','Registrado'];
  const rows=lista.map(r=>{ const c=clientePorId(r.clienteId)||{}; const info=estadoInfo(r); const vl=r.verificacionListas||{}; const ros=r.ros||{}; return [folioDe(r),info.estado,c.folio||'',c.nombre||'',c.rut||'',r.transferencia.fecha,r.beneficiario.nombre,r.beneficiario.documento,r.beneficiario.pais,r.beneficiario.banco,r.beneficiario.cuenta,r.transferencia.monto,r.transferencia.moneda,r.transferencia.montoDestino,r.transferencia.monedaDestino,r.transferencia.referencia,r.transferencia.canal,r.transferencia.proposito,r.transferencia.relacion,vl.requerida==='si'?'Sí':'No',vl.resultado||'',vl.comentario||'',r.pagoEfectivo==='si'?'Sí':'No',r.usdEquivalente||'',r.roeIncluir?'Sí':'No',ros.estado||'',ros.folio||ros.justificacion||'',info.comp?'Sí':'No',nFacturaDe(r),info.fact?'Sí':'No',(r.otros||[]).length,r.usuario||'',r.creadoEn]; });
  const csv=[cols,...rows].map(r=>r.map(c=>'"'+(c==null?'':c).toString().replace(/"/g,'""')+'"').join(',')).join('\n');
  descargarBlob(new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8;'}),'alun_transferencias_'+hoy()+'.csv');
}
function exportJSON(){
  const data={ version:3, exportado:new Date().toISOString(), clientes, registros, facturas, compras, movimientos, proveedores, cuenta, cuentasBancarias, cartolaLineas, config:{ultimoFolio:config.ultimoFolio,ultimoFolioCliente:config.ultimoFolioCliente,ultimoFolioFactura:config.ultimoFolioFactura,ultimoFolioCompra:config.ultimoFolioCompra,ultimoFolioMov:config.ultimoFolioMov,ultimoFolioCuenta:config.ultimoFolioCuenta,umbrales:config.umbrales,autoDescarga:config.autoDescarga} };
  descargarBlob(new Blob([JSON.stringify(data,null,2)],{type:'application/json'}),'alun_backup_'+hoy()+'.json');
}
function importarJSON(file){
  const rd=new FileReader();
  rd.onload=e=>{ try{
    const data=JSON.parse(e.target.result);
    if(Array.isArray(data)){ // respaldo antiguo (solo registros)
      const ex=new Set(registros.map(r=>r.id)); let n=0; data.forEach(r=>{ if(!ex.has(r.id)){registros.push(r);n++;} });
      migrar(); guardarDatos(); guardarClientes(); guardarConfigData(); alert('Importadas '+n+' transferencias (formato antiguo).');
    } else {
      const exC=new Set(clientes.map(c=>c.id)); (data.clientes||[]).forEach(c=>{ if(!exC.has(c.id)) clientes.push(c); });
      const exF=new Set(facturas.map(f=>f.id)); (data.facturas||[]).forEach(f=>{ if(!exF.has(f.id)) facturas.push(f); });
      const exCo=new Set(compras.map(x=>x.id)); (data.compras||[]).forEach(x=>{ if(!exCo.has(x.id)) compras.push(x); }); guardarCompras();
      const exMv=new Set(movimientos.map(x=>x.id)); (data.movimientos||[]).forEach(x=>{ if(!exMv.has(x.id)) movimientos.push(x); }); guardarMovimientos();
      const exPv=new Set(proveedores.map(x=>x.id)); (data.proveedores||[]).forEach(x=>{ if(!exPv.has(x.id)) proveedores.push(x); }); guardarProveedores();
      const exCu=new Set(cuenta.map(x=>x.id)); (data.cuenta||[]).forEach(x=>{ if(!exCu.has(x.id)) cuenta.push(x); }); guardarCuenta();
      const exCB=new Set(cuentasBancarias.map(x=>x.id)); (data.cuentasBancarias||[]).forEach(x=>{ if(!exCB.has(x.id)) cuentasBancarias.push(x); }); guardarCuentasBancarias();
      const exCt=new Set(cartolaLineas.map(x=>x.id)); (data.cartolaLineas||[]).forEach(x=>{ if(!exCt.has(x.id)) cartolaLineas.push(x); }); guardarCartola();
      const exR=new Set(registros.map(r=>r.id)); let n=0; (data.registros||[]).forEach(r=>{ if(!exR.has(r.id)){registros.push(r);n++;} });
      if(data.config){ ['ultimoFolio','ultimoFolioCliente','ultimoFolioFactura','ultimoFolioCompra','ultimoFolioMov','ultimoFolioCuenta'].forEach(k=>{ if(data.config[k]&&data.config[k]>(config[k]||0)) config[k]=data.config[k]; }); if(data.config.umbrales) config.umbrales=Object.assign(config.umbrales,data.config.umbrales); }
      guardarDatos(); guardarClientes(); guardarFacturas(); guardarConfigData();
      alert('Importación completa: '+(data.clientes||[]).length+' clientes, '+n+' transferencias, '+(data.facturas||[]).length+' facturas.');
    }
    actualizarDashboard(); verificarPendientes(); verificarAlertas();
  }catch(err){ alert('Archivo inválido. Use un JSON exportado desde este sistema.'); } };
  rd.readAsText(file);
}
function eliminarTodo(){
  if(!confirm('¿Eliminar TODOS los datos (clientes, transferencias y facturas)? Es irreversible.\nExporte un respaldo antes.')) return;
  // Retención UAF (5 años): se descarga un respaldo antes y se exige confirmación escrita.
  const t=prompt('La normativa UAF exige conservar los registros por 5 años.\nSe descargará un respaldo JSON automáticamente antes de limpiar.\n\nEscriba ELIMINAR para confirmar:');
  if(t!=='ELIMINAR'){ alert('Operación cancelada.'); return; }
  try{ exportJSON(); }catch(e){}
  registros=[]; clientes=[]; facturas=[]; compras=[]; movimientos=[]; proveedores=[]; cuenta=[];
  guardarDatos(); guardarClientes(); guardarFacturas(); guardarCompras(); guardarMovimientos(); guardarProveedores(); guardarCuenta(); cuentasBancarias=[]; guardarCuentasBancarias(); cartolaLineas=[]; guardarCartola();
  actualizarDashboard(); verificarPendientes(); verificarAlertas(); renderRegistros([]);
}

// ═══════════════ MIGRACIÓN (datos antiguos) ═══════════════
function migrar(){
  let ch=false;
  registros.forEach(r=>{
    if(!r.clienteId && r.ordenante){
      let c=clientes.find(x=>x.rut&&r.ordenante.rut&&x.rut===r.ordenante.rut);
      if(!c){ c={ id:'c'+Date.now()+Math.floor(Math.random()*9999), folio:nuevoFolioCliente(), creadoEn:new Date().toISOString(), tipoPersona:'natural', nombre:r.ordenante.nombre||'', rut:r.ordenante.rut||'', nacimiento:r.ordenante.nacimiento||'', nacionalidad:r.ordenante.nacionalidad||'', direccion:r.ordenante.direccion||'', comuna:'', ciudad:'', pais:'Chile', telefono:r.ordenante.telefono||'', email:'', actividad:'', origenFondos:'', pep:'no', observaciones:'(migrado automáticamente)' }; clientes.push(c); }
      r.clienteId=c.id; ch=true;
    }
    if(r.archivos && !r.otros){ r.otros=r.archivos; ch=true; }
    if(r.comprobante===undefined){ r.comprobante=null; ch=true; }
    if(r.facturaModo===undefined){ r.facturaModo='individual'; r.facturaIndividual=null; r.facturaGrupoId=null; ch=true; }
    if(!r.otros) r.otros=[];
  });
  clientes.forEach(c=>{
    if(c.giro===undefined){ c.giro=c.actividad||''; ch=true; }
    if(!c.repLegal){ c.repLegal={}; ch=true; }
    if(!c.beneficiarios){ c.beneficiarios=[]; ch=true; }
    if(!c.docs){ c.docs={}; ch=true; }
    if(!c.perfil){ c.perfil={}; ch=true; }
    if(!c.interno){ c.interno={}; ch=true; }
    if(!c.habituales){ c.habituales={destinatarios:[]}; ch=true; }
    if(c.region===undefined){ c.region=c.ciudad||''; ch=true; }
  });
  if(ch){ guardarDatos(); guardarClientes(); guardarConfigData(); }
}

