function attachFileInputs(){
  const on=(id,fn)=>{ const e=document.getElementById(id); if(e) e.addEventListener('change',function(){ fn(this); this.value=''; }); };
  on('logoInput2',i=>manejarLogo(i));
  on('file-comprobante',i=>{ const f=i.files[0]; if(f) leerArchivo(f,o=>{archivosTx.comprobante=o; renderComprobante();}); });
  on('file-factura',i=>{ const f=i.files[0]; if(f) leerArchivo(f,o=>{archivosTx.factura=o; renderFactura();}); });
  on('file-nf',i=>{ const f=i.files[0]; if(f) leerArchivo(f,o=>{archivosTx.nuevaFactura=o; renderNF(); actualizarTagFactura();}); });
  on('file-otros',i=>{ Array.from(i.files).forEach(f=>leerArchivo(f,o=>{archivosTx.otros.push(o); renderOtros();})); });
  on('file-fac',i=>{ const f=i.files[0]; if(f) leerArchivo(f,o=>{archivoFacManual=o; document.getElementById('list-fac').innerHTML=chip(o,"archivoFacManual=null;document.getElementById('list-fac').innerHTML='';");}); });
  on('importInput',i=>{ const f=i.files[0]; if(f) importarJSON(f); });
  on('file-import-pdf',i=>{ const f=i.files[0]; if(f) importarFichaPDF(f); });
  on('file-abono',i=>{ const f=i.files[0]; if(f) leerArchivo(f,o=>{ archivoAbono=o; const el=document.getElementById('ab-file'); if(el) el.innerHTML=chip(o,"archivoAbono=null;document.getElementById('ab-file').innerHTML='';"); }); });
  on('file-cuenta',i=>{ const f=i.files[0]; if(f) leerArchivo(f,o=>{ archivoCuenta=o; const el=document.getElementById('cu-file'); if(el) el.innerHTML=chip(o,"archivoCuenta=null;document.getElementById('cu-file').innerHTML='';"); }); });
  on('file-cartola',i=>{ const f=i.files[0]; if(f){ const r=new FileReader(); r.onload=e=>procesarTextoCartola(e.target.result); r.readAsText(f); } });
  on('file-cedulaRL',i=>{const f=i.files[0]; if(f) leerArchivo(f,o=>{clienteDocs.cedulaRL=o; renderDocCliente();});});
  on('file-constitucion',i=>{const f=i.files[0]; if(f) leerArchivo(f,o=>{clienteDocs.constitucion=o; renderDocCliente();});});
  on('file-modificaciones',i=>{Array.from(i.files).forEach(f=>leerArchivo(f,o=>{clienteDocs.modificaciones.push(o); renderDocCliente();}));});
  on('file-vigencia',i=>{const f=i.files[0]; if(f) leerArchivo(f,o=>{clienteDocs.vigencia=o; renderDocCliente();});});
  on('file-erut',i=>{const f=i.files[0]; if(f) leerArchivo(f,o=>{clienteDocs.erut=o; renderDocCliente();});});
  on('file-kyb',i=>{const f=i.files[0]; if(f) leerArchivo(f,o=>{clienteDocs.kyb=o; renderDocCliente();});});
  on('file-cedula-titular',i=>{const f=i.files[0]; if(f) leerArchivo(f,o=>{clienteDocs.cedulaTitular=o; renderDocCliente();});});
  on('file-ficha-firmada',i=>{const f=i.files[0]; if(f) leerArchivo(f,o=>{clienteDocs.fichaFirmada=o; renderDocCliente();});});
  on('file-adicionales',i=>{Array.from(i.files).forEach(f=>leerArchivo(f,o=>{clienteDocs.adicionales.push(o); renderDocCliente();}));});
  on('file-bf-cedula',i=>{const f=i.files[0]; if(f&&bfUploadTarget){const t=bfUploadTarget; leerArchivo(f,o=>{if(clienteBeneficiarios[t.idx]) clienteBeneficiarios[t.idx].cedula=o; renderBeneficiarios(); bfUploadTarget=null;});}});
  on('file-bf-kyc',i=>{const f=i.files[0]; if(f&&bfUploadTarget){const t=bfUploadTarget; leerArchivo(f,o=>{if(clienteBeneficiarios[t.idx]) clienteBeneficiarios[t.idx].kyc=o; renderBeneficiarios(); bfUploadTarget=null;});}});
  // input oculto para reemplazar documento de factura existente
  const rep=document.createElement('input'); rep.type='file'; rep.id='file-fac-replace'; rep.style.display='none'; rep.accept='.pdf,.jpg,.jpeg,.png,.webp,.heic,.docx,.doc';
  rep.addEventListener('change',function(){ const f=this.files[0]; if(f&&subiendoFacturaId) leerArchivo(f,o=>{ const g=facturaPorId(subiendoFacturaId); if(g){ g.archivo=o; guardarFacturas(); renderFacturas(); actualizarDashboard(); } subiendoFacturaId=null; }); this.value=''; });
  document.body.appendChild(rep);
}

// ═══════════════ MODAL ═══════════════
function cerrarModal(){ document.getElementById('modal-overlay').classList.remove('open'); }

// ═══════════════ INIT ═══════════════
// ═══════════════ COMPRAS, ABONOS Y SALDOS ═══════════════
let compras = [];
let archivoAbono = null;
let compraVerId = null;
let tipoOperacionActual = 'compra_div';
function guardarCompras(){ try{ localStorage.setItem('alun_compras', JSON.stringify(compras)); }catch(e){} }
function nuevoFolioCompra(){ config.ultimoFolioCompra=(config.ultimoFolioCompra||0)+1; return 'CO-'+String(config.ultimoFolioCompra).padStart(6,'0'); }
function compraPorId(id){ return compras.find(c=>c.id===id); }

function abonosTotal(c){ return (c.abonos||[]).reduce((s,a)=>s+(parseFloat(a.monto)||0),0); }
function comisionMontoCompra(c){ const base=(parseFloat(c.montoCompra)||0)*(parseFloat(c.tipoCambio)||1); if(c.comisionTipo==='porcentaje') return base*((parseFloat(c.comision)||0)/100); return parseFloat(c.comision)||0; }
function montoRequeridoCompra(c){
  if(c.tipoOperacion==='venta_div'){ const tc=parseFloat(c.tipoCambio)||1; return (parseFloat(c.montoCompra)||0)/(tc||1); }
  if(c.tipoOperacion==='liq'){ return parseFloat(c.montoLiquidar)||0; }
  return (parseFloat(c.montoCompra)||0)*(parseFloat(c.tipoCambio)||1)+comisionMontoCompra(c);
}
function gananciaCompra(c){
  if(c.tipoOperacion==='compra_div') return ((parseFloat(c.tipoCambio)||0)-(parseFloat(c.tcProveedor)||0))*(parseFloat(c.montoCompra)||0);
  if(c.tipoOperacion==='venta_div'){ const u=montoRequeridoCompra(c); return ((parseFloat(c.tcProveedor)||0)-(parseFloat(c.tipoCambio)||0))*u; }
  if(c.tipoOperacion==='liq') return ((parseFloat(c.montoLiquidar)||0)*(parseFloat(c.liqTcVenta)||0)) - (parseFloat(c.liqClpPago)||0);
  return 0;
}
function compraFundeada(c){ return abonosTotal(c) >= montoRequeridoCompra(c)-0.001; }
function saldoPorPagarCompra(c){ return Math.max(0, montoRequeridoCompra(c)-abonosTotal(c)); }
function saldoAFavorCompra(c){ return Math.max(0, abonosTotal(c)-montoRequeridoCompra(c)); }
function transferidoDeCompra(c, exceptId){ return registros.filter(r=>r.compraId===c.id && r.id!==exceptId).reduce((s,r)=>s+(parseFloat(r.transferencia.monto)||0),0); }
function saldoPorTransferirCompra(c, exceptId){ return (parseFloat(c.montoCompra)||0)-transferidoDeCompra(c, exceptId); }
function estadoPagoCompra(c){ return compraFundeada(c)?'pagada':(abonosTotal(c)>0?'parcial':'pendiente'); }
function fechaLimiteCompra(c){ const d=new Date((c.fecha||hoy())+'T00:00:00'); d.setHours(d.getHours()+(parseInt(c.valuta)||0)); return d; }
function compraVencidaSinPago(c){ return !compraFundeada(c) && new Date() > fechaLimiteCompra(c); }
function colorEstado(ep){ return ep==='pagada'?'verde':ep==='parcial'?'amarillo':'rojo'; }
function tipoOperacionTxt(c){ return c.tipoOperacion==='venta_div'?'Venta de divisa':c.tipoOperacion==='liq'?'Liquidación / conversión':'Compra de divisa'; }

function setTipoOperacion(t){
  tipoOperacionActual=t;
  document.getElementById('op-rc-compra').classList.toggle('active', t==='compra_div');
  document.getElementById('op-rc-venta').classList.toggle('active', t==='venta_div');
  document.getElementById('op-rc-liq').classList.toggle('active', t==='liq');
  document.querySelectorAll('.op-compra').forEach(e=>e.style.display=t==='compra_div'?'block':'none');
  document.querySelectorAll('.op-venta').forEach(e=>e.style.display=t==='venta_div'?'block':'none');
  document.querySelectorAll('.op-liq').forEach(e=>e.style.display=t==='liq'?'block':'none');
  recalcOperacion();
}
function recalcOperacion(campo){
  const res=document.getElementById('op-resumen'); if(!res) return;
  const t=tipoOperacionActual;
  if(t==='compra_div'){
    const tc=parseFloat(v('cd-tccli'))||0, tcp=parseFloat(v('cd-tcprov'))||0;
    let monto=parseFloat(v('cd-monto'))||0, clp=parseFloat(v('cd-clp'))||0;
    if(campo==='clp' && tc>0){ monto=clp/tc; const e=document.getElementById('cd-monto'); if(e) e.value=monto?monto.toFixed(2):''; }
    else if(tc>0){ clp=monto*tc; const e=document.getElementById('cd-clp'); if(e) e.value=clp?clp.toFixed(0):''; }
    const gan=(tc-tcp)*monto;
    res.innerHTML='El cliente debe abonar <strong>'+fmtNum(clp,0)+' CLP</strong> para recibir <strong>'+fmtNum(monto,2)+' '+esc(v('cd-moneda'))+'</strong>.'+(tcp>0?' Ganancia estimada: <strong>'+fmtNum(gan,0)+' CLP</strong>.':'');
  } else if(t==='venta_div'){
    const tc=parseFloat(v('vd-tccli'))||0, tcp=parseFloat(v('vd-tcprov'))||0;
    let monto=parseFloat(v('vd-monto'))||0, clp=parseFloat(v('vd-clp'))||0;
    if(campo==='clp' && tc>0){ monto=clp/tc; const e=document.getElementById('vd-monto'); if(e) e.value=monto?monto.toFixed(2):''; }
    else if(tc>0){ clp=monto*tc; const e=document.getElementById('vd-clp'); if(e) e.value=clp?clp.toFixed(0):''; }
    const gan=(tcp-tc)*monto;
    res.innerHTML='El cliente debe abonar <strong>'+fmtNum(monto,2)+' '+esc(v('vd-moneda'))+'</strong> para recibir <strong>'+fmtNum(clp,0)+' CLP</strong>.'+(tcp>0?' Ganancia estimada: <strong>'+fmtNum(gan,0)+' CLP</strong>.':'');
  } else if(t==='liq'){
    const com=parseFloat(v('lq-com'))||0, factor=1-com/100;
    let monto=parseFloat(v('lq-monto'))||0, dest=parseFloat(v('lq-destmonto'))||0;
    if(campo==='dest'){ monto = factor>0? dest/factor : 0; const me=document.getElementById('lq-monto'); if(me) me.value=monto?monto.toFixed(2):''; }
    else if(campo==='monto'||campo==='com'){ dest = monto*factor; const de=document.getElementById('lq-destmonto'); if(de) de.value=dest?dest.toFixed(2):''; }
    const tcv=parseFloat(v('lq-tcventa'))||0, tcc=parseFloat(v('lq-tccompra'))||0;
    let clppago=dest*tcc; const ce=document.getElementById('lq-clppago'); if(ce) ce.value=(dest>0&&tcc>0)?clppago.toFixed(0):'';
    const clpventa=monto*tcv, gan=clpventa-clppago;
    res.innerHTML='Entregar <strong>'+fmtNum(dest,2)+' '+esc(v('lq-destino'))+'</strong> por <strong>'+fmtNum(monto,2)+' '+esc(v('lq-origen'))+'</strong>.'+((tcv>0||clppago>0)?' Venta origen: '+fmtNum(clpventa,0)+' CLP · Compra destino: '+fmtNum(clppago,0)+' CLP · <strong>Ganancia: '+fmtNum(gan,0)+' CLP</strong>.':'');
  }
}
function recalcMontoRequerido(){ recalcOperacion(); }

function poblarSelectsCompra(){
  const sel=document.getElementById('co-cliente'); if(sel){ const prev=sel.value; sel.innerHTML='<option value="">— Seleccione cliente —</option>'+clientes.map(c=>'<option value="'+c.id+'">'+esc(c.nombre)+' ('+esc(c.folio)+')</option>').join(''); sel.value=prev; }
}
function crearCompra(){
  const cli=v('co-cliente'); if(!cli){ alert('Seleccione el cliente.'); return; }
  const t=tipoOperacionActual;
  let c={ id:'co'+Date.now(), folio:nuevoFolioCompra(), creadoEn:new Date().toISOString(), usuario:usuarioActual(), clienteId:cli, fecha:v('co-fecha')||hoy(), valuta:parseInt(v('co-valuta'))||0, observaciones:v('co-obs'), tipoOperacion:t, comision:0, comisionTipo:'monto', abonos:[] };
  if(t==='compra_div'){
    const monto=parseFloat(v('cd-monto'))||0; if(monto<=0){ alert('Ingrese el monto de divisa que compra el cliente.'); return; }
    c.monedaCompra=v('cd-moneda'); c.montoCompra=monto; c.monedaPago='CLP'; c.tipoCambio=parseFloat(v('cd-tccli'))||0; c.tcProveedor=parseFloat(v('cd-tcprov'))||0; c.contraparte=v('cd-contra');
  } else if(t==='venta_div'){
    const monto=parseFloat(v('vd-monto'))||0, clp=parseFloat(v('vd-clp'))||0; if(monto<=0){ alert('Ingrese el monto de divisa que vende el cliente.'); return; }
    c.monedaCompra='CLP'; c.montoCompra=clp; c.monedaPago=v('vd-moneda'); c.tipoCambio=parseFloat(v('vd-tccli'))||0; c.tcProveedor=parseFloat(v('vd-tcprov'))||0; c.contraparte=v('vd-contra');
  } else {
    const monto=parseFloat(v('lq-monto'))||0; const com=parseFloat(v('lq-com'))||0;
    const dest=parseFloat(v('lq-destmonto'))|| (monto*(1-com/100));
    if(monto<=0||dest<=0){ alert('Ingrese el monto a liquidar o el monto a entregar.'); return; }
    c.monedaPago=v('lq-origen'); c.monedaCompra=v('lq-destino'); c.montoCompra=dest; c.tipoCambio=1;
    c.montoLiquidar=monto; c.liqComisionPct=com; c.liqTcVenta=parseFloat(v('lq-tcventa'))||0; c.liqContraparteVenta=v('lq-contraventa'); c.liqTcCompra=parseFloat(v('lq-tccompra'))||0; c.liqClpPago=dest*(parseFloat(v('lq-tccompra'))||0); c.liqContraparteCompra=v('lq-contracompra');
  }
  c.gananciaCLP=gananciaCompra(c);
  compras.unshift(c); guardarCompras(); guardarConfigData();
  ['cd-monto','cd-clp','vd-monto','vd-clp','lq-monto','lq-destmonto','lq-clppago','co-obs'].forEach(id=>{const e=document.getElementById(id); if(e)e.value='';});
  document.getElementById('co-fecha').value=hoy(); recalcOperacion();
  renderCompras(); renderSaldos(); actualizarDashboard();
  alert('Operación creada: '+c.folio+'. Ganancia estimada: '+fmtNum(c.gananciaCLP||0,0)+' CLP. Ahora registre los abonos del cliente.');
}

function renderCompras(){
  const el=document.getElementById('compras-list'); if(!el) return;
  const q=v('co-search').toLowerCase();
  let lista=compras;
  if(q) lista=lista.filter(c=>{const cl=clientePorId(c.clienteId)||{}; return (cl.nombre||'').toLowerCase().includes(q)||(c.folio||'').toLowerCase().includes(q)||(c.monedaCompra||'').toLowerCase().includes(q);});
  if(!lista.length){ el.innerHTML='<div class="empty-state"><i class="ti ti-shopping-cart-off"></i><p>No hay operaciones registradas.</p></div>'; return; }
  el.innerHTML=lista.map(c=>{
    const ep=estadoPagoCompra(c), col=colorEstado(ep);
    const venc=compraVencidaSinPago(c), spt=saldoPorTransferirCompra(c), favor=saldoAFavorCompra(c), gan=gananciaCompra(c);
    return '<div class="record-row"><div class="record-icon"><i class="ti ti-shopping-cart"></i></div>'+
      '<div class="record-info"><h3>'+esc(clienteNombre(c.clienteId))+' · <strong>'+fmtNum(c.montoCompra)+' '+esc(c.monedaCompra)+'</strong> <span class="badge tag-natural status-pill" style="font-size:10px;">'+tipoOperacionTxt(c)+'</span></h3>'+
      '<div class="record-detail">Paga en '+esc(c.monedaPago)+' · valuta '+esc(c.valuta)+'h · Pagado '+fmtNum(abonosTotal(c),2)+' / '+fmtNum(montoRequeridoCompra(c),2)+' '+esc(c.monedaPago)+(favor>0?' · <span style="color:#27500A;">a favor '+fmtNum(favor,2)+'</span>':'')+' · Ganancia '+fmtNum(gan,0)+' CLP</div>'+
      '<div class="record-meta"><span class="badge badge-amber">'+esc(c.folio)+'</span> · <span class="status-pill pill-'+col+'"><span class="status-dot status-'+col+'"></span>'+(ep==='pagada'?'Pagada':ep==='parcial'?'Pago parcial':'Sin pago')+'</span>'+(venc?' <span class="status-pill pill-rojo">vencida</span>':'')+' · Por transferir: <strong>'+fmtNum(spt)+' '+esc(c.monedaCompra)+'</strong></div>'+
      '</div><div class="record-actions">'+
      '<button class="btn btn-secondary btn-sm" onclick="verCompra(\''+c.id+'\')" title="Ver / abonar"><i class="ti ti-eye"></i></button>'+
      '<button class="btn btn-danger btn-sm" onclick="eliminarCompra(\''+c.id+'\')" title="Eliminar"><i class="ti ti-trash"></i></button>'+
      '</div></div>';
  }).join('');
}
function eliminarCompra(id){
  if(registros.some(r=>r.compraId===id)){ alert('No se puede eliminar: hay transferencias asociadas a esta operación.'); return; }
  const co=compraPorId(id); const m=pedirMotivo('¿Eliminar esta operación y sus abonos?'); if(m===null) return; archivar('compra', co, m);
  compras=compras.filter(c=>c.id!==id); guardarCompras(); renderCompras(); renderSaldos(); actualizarDashboard();
}
function verCompra(id){
  const c=compraPorId(id); if(!c) return; compraVerId=id;
  const row=(l,val)=>'<div class="detail-row"><span class="detail-label">'+l+'</span><span class="detail-value">'+esc(val)+'</span></div>';
  const req=montoRequeridoCompra(c), pag=abonosTotal(c), porPagar=saldoPorPagarCompra(c), favor=saldoAFavorCompra(c);
  const spt=saldoPorTransferirCompra(c), trans=transferidoDeCompra(c), ep=estadoPagoCompra(c), col=colorEstado(ep), gan=gananciaCompra(c);
  const abonosHtml=(c.abonos||[]).length ? c.abonos.map((a,i)=>'<div class="file-item"><i class="ti '+((parseFloat(a.monto)||0)<0?'ti-arrow-up-right':'ti-cash')+'"></i><span>'+esc(a.fecha)+' · <strong>'+fmtNum(a.monto,2)+' '+esc(c.monedaPago)+'</strong>'+(a.medio?' · '+esc(a.medio):'')+(a.observacion?' · '+esc(a.observacion):'')+'</span>'+(a.comprobante&&a.comprobante.data?'<button class="btn btn-secondary btn-sm" onclick="descargarAbono(\''+id+'\','+i+')"><i class="ti ti-download"></i></button>':'')+'<button class="btn btn-danger btn-sm" onclick="quitarAbono(\''+id+'\','+i+')"><i class="ti ti-x"></i></button></div>').join('') : '<p style="font-size:12px;color:var(--text-muted);">Sin abonos registrados.</p>';
  const txList=registros.filter(r=>r.compraId===id);
  const txHtml=txList.length ? txList.map(r=>'<div class="file-item"><i class="ti ti-transfer"></i><span>'+esc(folioDe(r))+' · '+fmtNum(r.transferencia.monto)+' '+esc(r.transferencia.moneda)+' → '+esc(r.beneficiario.nombre)+'</span></div>').join('') : '<p style="font-size:12px;color:var(--text-muted);">Sin transferencias asociadas.</p>';
  const credSrc=compras.filter(x=>x.clienteId===c.clienteId && x.id!==id && saldoAFavorCompra(x)>0.001 && x.monedaPago===c.monedaPago);
  const dispCuenta = (typeof saldoCuentaCliente==='function') ? saldoCuentaCliente(c.clienteId, c.monedaPago) : 0;
  const cuentaSel = dispCuenta>0.001 ? '<div style="margin-top:10px;padding-top:10px;border-top:0.5px solid var(--border);"><label style="font-size:12px;color:var(--text-muted);">Aplicar saldo en cuenta del cliente ('+fmtNum(dispCuenta,2)+' '+esc(c.monedaPago)+' disponible):</label><div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:4px;"><input type="number" id="cuenta-aplicar-monto" placeholder="Monto" style="width:130px;padding:7px;border:0.5px solid var(--border-strong);border-radius:6px;"><button class="btn btn-secondary btn-sm" onclick="aplicarSaldoCuenta(\''+id+'\')"><i class="ti ti-wallet"></i> Aplicar desde cuenta</button></div></div>' : '';
  const credSel=credSrc.length ? '<div style="margin-top:10px;"><label style="font-size:12px;color:var(--text-muted);">O aplicar saldo a favor de otra operación ('+esc(c.monedaPago)+'):</label><div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:4px;"><select id="ab-credito" style="flex:1;min-width:150px;padding:7px;border:0.5px solid var(--border-strong);border-radius:6px;">'+credSrc.map(x=>'<option value="'+x.id+'">'+esc(x.folio)+' · disp. '+fmtNum(saldoAFavorCompra(x),2)+' '+esc(x.monedaPago)+'</option>').join('')+'</select><input type="number" id="ab-credito-monto" placeholder="Monto" style="width:110px;padding:7px;border:0.5px solid var(--border-strong);border-radius:6px;"><button class="btn btn-secondary btn-sm" onclick="aplicarSaldoAFavor(\''+id+'\')"><i class="ti ti-transfer-in"></i> Aplicar</button></div></div>' : '';
  let opDetalle = c.tipoOperacion==='liq'
    ? row('Convierte',fmtNum(c.montoLiquidar)+' '+c.monedaPago+' → '+fmtNum(c.montoCompra)+' '+c.monedaCompra+' (comisión '+(c.liqComisionPct||0)+'%)')+row('TC venta origen',c.liqTcVenta)+row('Contraparte venta',c.liqContraparteVenta)+row('TC compra destino',c.liqTcCompra)+row('CLP pagado destino',fmtNum(c.liqClpPago,0))+row('Contraparte compra',c.liqContraparteCompra)
    : row('TC al cliente',c.tipoCambio)+row('TC proveedor',c.tcProveedor)+row('Contraparte',c.contraparte);
  document.getElementById('modal-content').innerHTML=
    '<div class="modal-title"><i class="ti ti-shopping-cart" style="color:var(--blue);vertical-align:-2px;margin-right:6px;"></i>'+esc(c.folio)+' <span class="status-pill pill-'+col+'" style="margin-left:6px;"><span class="status-dot status-'+col+'"></span>'+(ep==='pagada'?'Pagada':ep==='parcial'?'Pago parcial':'Sin pago')+'</span></div>'+
    '<div class="detail-section">Operación</div>'+row('Tipo',tipoOperacionTxt(c))+row('Cliente',clienteNombre(c.clienteId))+row('Fecha',c.fecha)+row('Recibe / compra',fmtNum(c.montoCompra)+' '+c.monedaCompra)+row('Paga en',c.monedaPago)+row('Valuta',c.valuta+' horas')+row('Límite de pago',fechaLimiteCompra(c).toLocaleString('es-CL'))+opDetalle+
    '<div class="alert-box '+(gan>=0?'alert-success':'alert-danger')+'" style="margin-top:8px;"><i class="ti ti-coin"></i><div>Ganancia estimada de la operación: <strong>'+fmtNum(gan,0)+' CLP</strong></div></div>'+'<div style="margin-top:8px;"><button class="btn btn-secondary btn-sm" onclick="registrarGananciaEnLibro(\''+id+'\')"><i class="ti ti-book"></i> Registrar ganancia en el libro de caja</button></div>'+
    '<div class="detail-section">Saldos de pago</div>'+row('Monto requerido',fmtNum(req,2)+' '+c.monedaPago)+row('Pagado',fmtNum(pag,2)+' '+c.monedaPago)+row('Saldo por pagar',fmtNum(porPagar,2)+' '+c.monedaPago)+(favor>0?row('Saldo a favor',fmtNum(favor,2)+' '+c.monedaPago)+'<div style="margin:4px 0 8px;"><button class="btn btn-secondary btn-sm" onclick="pasarSaldoAFavorACuenta(\''+id+'\')"><i class="ti ti-wallet"></i> Pasar saldo a favor a la cuenta del cliente</button></div>':'')+
    '<div class="detail-section">Saldos por transferir</div>'+row('Comprado',fmtNum(c.montoCompra)+' '+c.monedaCompra)+row('Transferido',fmtNum(trans)+' '+c.monedaCompra)+row('Disponible',fmtNum(spt)+' '+c.monedaCompra)+
    (compraFundeada(c)?'':'<div class="alert-box alert-warning" style="margin-top:8px;"><i class="ti ti-alert-triangle"></i><div>Operación sin pago completo: no se podrán ejecutar transferencias hasta cubrir el monto requerido.</div></div>')+
    '<div class="detail-section">Registrar abono</div>'+
    '<div class="form-grid"><div class="form-group"><label>Fecha</label><input type="date" id="ab-fecha"></div><div class="form-group"><label>Monto ('+esc(c.monedaPago)+')</label><input type="number" id="ab-monto" min="0" step="0.01" placeholder="0.00"></div><div class="form-group"><label>Medio</label><input type="text" id="ab-medio" placeholder="Transferencia, efectivo..."></div></div>'+
    '<div class="form-group" style="margin-top:8px;"><label>Observación</label><input type="text" id="ab-obs" placeholder="Opcional"></div>'+
    '<label class="mini-upload" style="margin-top:8px;" onclick="document.getElementById(\'file-abono\').click()"><i class="ti ti-upload"></i> Comprobante del abono (opcional)</label><div id="ab-file" style="margin-top:6px;"></div>'+
    '<div class="actions" style="margin-top:10px;"><button class="btn btn-primary btn-sm" onclick="registrarAbono(\''+id+'\')"><i class="ti ti-plus"></i> Agregar abono</button></div>'+cuentaSel+credSel+
    '<div class="detail-section">Abonos</div><div class="file-list">'+abonosHtml+'</div>'+
    '<div class="detail-section">Transferencias asociadas</div><div class="file-list">'+txHtml+'</div>';
  document.getElementById('modal-overlay').classList.add('open');
  setTimeout(()=>{ const f=document.getElementById('ab-fecha'); if(f) f.value=hoy(); },40);
  archivoAbono=null;
}
function registrarAbono(id){
  const c=compraPorId(id); if(!c) return;
  const monto=parseFloat(v('ab-monto'))||0; if(monto<=0){ alert('Ingrese el monto del abono.'); return; }
  if(!c.abonos) c.abonos=[];
  c.abonos.push({ id:'ab'+Date.now(), fecha:v('ab-fecha')||hoy(), monto:monto, medio:v('ab-medio'), observacion:v('ab-obs'), comprobante:archivoAbono, usuario:usuarioActual() });
  guardarCompras(); archivoAbono=null; renderCompras(); renderSaldos(); actualizarDashboard(); verCompra(id);
}
function quitarAbono(id,i){ const c=compraPorId(id); if(!c) return; if(!confirm('¿Eliminar este abono?')) return; c.abonos.splice(i,1); guardarCompras(); renderCompras(); renderSaldos(); verCompra(id); }
function descargarAbono(id,i){ const c=compraPorId(id); if(!c) return; const a=(c.abonos||[])[i]; if(a&&a.comprobante&&a.comprobante.data) descargarBlobData(a.comprobante.data,a.comprobante.nombre); }
function aplicarSaldoAFavor(destId){
  const dest=compraPorId(destId); if(!dest) return;
  const srcId=v('ab-credito'), amt=parseFloat(v('ab-credito-monto'))||0;
  if(!srcId||amt<=0){ alert('Seleccione la operación origen y el monto a aplicar.'); return; }
  const src=compraPorId(srcId); if(!src) return;
  const favor=saldoAFavorCompra(src);
  if(amt>favor+0.001){ alert('El monto excede el saldo a favor disponible ('+fmtNum(favor,2)+' '+src.monedaPago+').'); return; }
  if(src.monedaPago!==dest.monedaPago){ alert('Las monedas de pago no coinciden ('+src.monedaPago+' vs '+dest.monedaPago+').'); return; }
  if(!src.abonos) src.abonos=[]; if(!dest.abonos) dest.abonos=[];
  src.abonos.push({ id:'ab'+Date.now(), fecha:hoy(), monto:-amt, medio:'Saldo a favor aplicado a '+dest.folio, tipo:'retiro_credito' });
  dest.abonos.push({ id:'ab'+(Date.now()+1), fecha:hoy(), monto:amt, medio:'Saldo a favor de '+src.folio, tipo:'credito_aplicado' });
  guardarCompras(); renderCompras(); renderSaldos(); actualizarDashboard(); verCompra(destId);
}

function renderSaldos(){
  const el=document.getElementById('saldos-list'); if(!el) return;
  const porCli={}; compras.forEach(c=>{ (porCli[c.clienteId]=porCli[c.clienteId]||[]).push(c); });
  const ids=Object.keys(porCli);
  if(!ids.length){ el.innerHTML='<div class="empty-state"><i class="ti ti-scale"></i><p>Aún no hay operaciones para mostrar saldos.</p></div>'; return; }
  el.innerHTML=ids.map(cid=>{
    const cl=clientePorId(cid)||{}, cs=porCli[cid];
    let favores={}, porTransf={}, pend=0, ganTotal=0;
    cs.forEach(c=>{ const fav=saldoAFavorCompra(c); if(fav>0.001){ favores[c.monedaPago]=(favores[c.monedaPago]||0)+fav; } const m=c.monedaCompra; porTransf[m]=(porTransf[m]||0)+saldoPorTransferirCompra(c); if(!compraFundeada(c)) pend++; ganTotal+=gananciaCompra(c); });
    const ptStr=Object.entries(porTransf).filter(([m,x])=>x>0.001).map(([m,x])=>fmtNum(x)+' '+m).join(', ')||'—';
    const salCta=(typeof saldosCuentaCliente==='function')?saldosCuentaCliente(cid):{}; const ctaStr=Object.entries(salCta).filter(([m,x])=>Math.abs(x)>0.001).map(([m,x])=>fmtNum(x,2)+' '+m).join(', ');
    const favStr=Object.entries(favores).map(([m,x])=>fmtNum(x,2)+' '+m).join(', ');
    return '<div class="record-row"><div class="record-icon"><i class="ti ti-scale"></i></div>'+
      '<div class="record-info"><h3>'+esc(cl.nombre||'(cliente)')+'</h3>'+
      '<div class="record-detail">'+cs.length+' operación(es) · Por transferir: <strong>'+ptStr+'</strong>'+(favStr?' · Saldo a favor: <strong style="color:#27500A;">'+favStr+'</strong>':'')+(ctaStr?' · En cuenta: <strong style="color:#27500A;">'+ctaStr+'</strong>':'')+' · Ganancia acum.: <strong>'+fmtNum(ganTotal,0)+' CLP</strong></div>'+
      '<div class="record-meta">'+(pend>0?'<span class="status-pill pill-amarillo">'+pend+' operación(es) sin pago completo</span>':'<span class="status-pill pill-verde">todas pagadas</span>')+'</div>'+
      '</div></div>';
  }).join('');
}

function poblarComprasTx(){
  const sel=document.getElementById('tx-compra'); if(!sel) return;
  if(!clienteSeleccionadoId){ sel.innerHTML='<option value="">— Seleccione primero el cliente —</option>'; const inf=document.getElementById('tx-compra-info'); if(inf) inf.innerHTML=''; return; }
  const disp=compras.filter(c=>c.clienteId===clienteSeleccionadoId);
  let html='<option value="">Sin asociar (transferencia directa)</option>';
  disp.forEach(c=>{ const spt=saldoPorTransferirCompra(c); html+='<option value="'+c.id+'">'+esc(c.folio)+' · '+fmtNum(c.montoCompra)+' '+esc(c.monedaCompra)+' · disp. '+fmtNum(spt)+(compraFundeada(c)?'':' (sin pagar)')+'</option>'; });
  sel.innerHTML=html; onSelectCompraTx();
}
function onSelectCompraTx(){
  const id=v('tx-compra'); const info=document.getElementById('tx-compra-info'); if(!info) return;
  if(!id){ info.innerHTML='<span style="font-size:12px;color:var(--text-muted);">Transferencia sin compra asociada (no controla saldos).</span>'; return; }
  const c=compraPorId(id); if(!c){ info.innerHTML=''; return; }
  const spt=saldoPorTransferirCompra(c, editandoId), f=compraFundeada(c);
  const mon=document.getElementById('tx-moneda'); if(mon) mon.value=c.monedaCompra;
  info.innerHTML=(f?'<span class="status-pill pill-verde"><span class="status-dot status-verde"></span>Operación pagada</span>':'<span class="status-pill pill-rojo"><span class="status-dot status-rojo"></span>Operación SIN pagar — no se podrá ejecutar</span>')+' · Disponible por transferir: <strong>'+fmtNum(spt)+' '+esc(c.monedaCompra)+'</strong>';
}

// ═══════════════ RESULTADOS / GANANCIAS ═══════════════
function comprasEnRango(desde,hasta){ return compras.filter(c=>{ const f=c.fecha||(c.creadoEn||'').slice(0,10); return (!desde||f>=desde)&&(!hasta||f<=hasta); }); }
function sumGanancia(lista){ return lista.reduce((s,c)=>s+gananciaCompra(c),0); }
function barChartGanancia(vals, year){
  const max=Math.max(1,...vals.map(x=>Math.abs(x)));
  const W=640,H=190,pad=26;
  const bw=(W-pad*2)/12;
  const meses=['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
  let bars='';
  vals.forEach((val,i)=>{ const h=Math.max(2, Math.abs(val)/max*(H-55)); const x=pad+i*bw+4; const y=H-32-h; const col=val<0?'#E24B4A':'#6E8169';
    bars+='<rect x="'+x+'" y="'+y+'" width="'+(bw-8)+'" height="'+h+'" rx="3" fill="'+col+'"></rect>';
    if(Math.abs(val)>0){ bars+='<text x="'+(x+(bw-8)/2)+'" y="'+(y-3)+'" font-size="8" text-anchor="middle" fill="#3E4D5C">'+(val>=1000000?(val/1000000).toFixed(1)+'M':val>=1000?Math.round(val/1000)+'k':Math.round(val))+'</text>'; }
    bars+='<text x="'+(x+(bw-8)/2)+'" y="'+(H-12)+'" font-size="9" text-anchor="middle" fill="#6b7280">'+meses[i]+'</text>'; });
  return '<svg viewBox="0 0 '+W+' '+H+'" style="width:100%;height:auto;"><text x="'+pad+'" y="14" font-size="11" fill="#6b7280">CLP por mes — '+year+'</text>'+bars+'</svg>';
}
function renderResultados(){
  if(!document.getElementById('res-total')) return;
  const modo=v('res-periodo'); const now=new Date(); const y=now.getFullYear(); const m=String(now.getMonth()+1).padStart(2,'0');
  let desde='', hasta='';
  if(modo==='mes'){ desde=y+'-'+m+'-01'; hasta=y+'-'+m+'-31'; }
  else if(modo==='anio'){ desde=y+'-01-01'; hasta=y+'-12-31'; }
  else if(modo==='rango'){ desde=v('res-desde'); hasta=v('res-hasta'); }
  document.getElementById('res-rango-box').style.display = modo==='rango'?'flex':'none';
  const lista=comprasEnRango(desde,hasta);
  const total=sumGanancia(lista);
  document.getElementById('res-total').textContent=fmtNum(total,0)+' CLP';
  document.getElementById('res-nops').textContent=lista.length;
  document.getElementById('res-prom').textContent=fmtNum(lista.length?total/lista.length:0,0);
  const porMes=new Array(12).fill(0);
  compras.forEach(c=>{ const f=c.fecha||(c.creadoEn||'').slice(0,10); if(f.slice(0,4)==String(y)){ const mi=parseInt(f.slice(5,7))-1; if(mi>=0&&mi<12) porMes[mi]+=gananciaCompra(c); } });
  document.getElementById('res-chart').innerHTML=barChartGanancia(porMes,y);
  const porCli={}; lista.forEach(c=>{ porCli[c.clienteId]=(porCli[c.clienteId]||0)+gananciaCompra(c); });
  const cliRows=Object.entries(porCli).sort((a,b)=>b[1]-a[1]);
  document.getElementById('res-cliente').innerHTML = cliRows.length ? cliRows.map(([id,g])=>'<div class="record-row" style="padding:9px 0;"><div class="record-info"><h3>'+esc(clienteNombre(id))+'</h3></div><div style="font-weight:600;color:'+(g<0?'#A32D2D':'#27500A')+';">'+fmtNum(g,0)+' CLP</div></div>').join('') : '<p style="font-size:12px;color:var(--text-muted);">Sin operaciones en el período.</p>';
  const tipos={compra_div:0,venta_div:0,liq:0}; lista.forEach(c=>{ const t=c.tipoOperacion||'compra_div'; tipos[t]=(tipos[t]||0)+gananciaCompra(c); });
  const tnames={compra_div:'Compra de divisa',venta_div:'Venta de divisa',liq:'Liquidación / conversión'};
  document.getElementById('res-tipo').innerHTML=['compra_div','venta_div','liq'].map(t=>'<div class="record-row" style="padding:9px 0;"><div class="record-info"><h3>'+tnames[t]+'</h3></div><div style="font-weight:600;color:'+((tipos[t]||0)<0?'#A32D2D':'#27500A')+';">'+fmtNum(tipos[t]||0,0)+' CLP</div></div>').join('');
}

// ═══════════════ LIBRO DE CAJA (INGRESOS / EGRESOS) ═══════════════
let movimientos = [];
function guardarMovimientos(){ try{ localStorage.setItem('alun_movimientos', JSON.stringify(movimientos)); }catch(e){} }
function nuevoFolioMov(){ config.ultimoFolioMov=(config.ultimoFolioMov||0)+1; return 'MOV-'+String(config.ultimoFolioMov).padStart(6,'0'); }
function poblarMovCliente(){ const sel=document.getElementById('mv-cliente'); if(sel){ const p=sel.value; sel.innerHTML='<option value="">— Seleccione —</option>'+clientes.map(c=>'<option value="'+c.id+'">'+esc(c.nombre)+'</option>').join(''); sel.value=p; } }
function onMovContraparte(){ const t=v('mv-cptipo'); const cb=document.getElementById('mv-cliente-box'), pb=document.getElementById('mv-proveedor-box'), tb=document.getElementById('mv-cptexto-box'); if(cb) cb.style.display=t==='cliente'?'flex':'none'; if(pb) pb.style.display=t==='proveedor'?'flex':'none'; if(tb) tb.style.display=t==='empresa'?'flex':'none'; }
function crearMovimiento(){
  const monto=parseFloat(v('mv-monto'))||0; if(monto<=0){ alert('Ingrese el monto del movimiento.'); return; }
  const cptipo=v('mv-cptipo');
  const m={ id:'mv'+Date.now(), folio:nuevoFolioMov(), creadoEn:new Date().toISOString(), fecha:v('mv-fecha')||hoy(), tipo:v('mv-tipo'), categoria:v('mv-categoria'), contraparteTipo:cptipo, contraparteId: cptipo==='cliente'?v('mv-cliente'):null, contraparteNombre: cptipo==='cliente'?clienteNombre(v('mv-cliente')):(cptipo==='proveedor'?v('mv-proveedor'):v('mv-cptexto')), monto:monto, moneda:v('mv-moneda'), descripcion:v('mv-desc'), conciliado:document.getElementById('mv-conciliado').checked };
  movimientos.unshift(m); guardarMovimientos(); guardarConfigData();
  ['mv-monto','mv-categoria','mv-cptexto','mv-desc'].forEach(id=>{const e=document.getElementById(id); if(e)e.value='';});
  document.getElementById('mv-conciliado').checked=false; document.getElementById('mv-fecha').value=hoy();
  renderMovimientos(); actualizarDashboard();
}
function eliminarMovimiento(id){ if(!confirm('¿Eliminar este movimiento?')) return; movimientos=movimientos.filter(m=>m.id!==id); guardarMovimientos(); renderMovimientos(); actualizarDashboard(); }
function toggleConciliado(id){ const m=movimientos.find(x=>x.id===id); if(m){ m.conciliado=!m.conciliado; guardarMovimientos(); renderMovimientos(); } }
function registrarGananciaEnLibro(compraId){
  const c=compraPorId(compraId); if(!c) return;
  const gan=Math.round(gananciaCompra(c));
  if(gan===0){ alert('Esta operación no tiene ganancia calculada.'); return; }
  movimientos.unshift({ id:'mv'+Date.now(), folio:nuevoFolioMov(), creadoEn:new Date().toISOString(), fecha:c.fecha||hoy(), tipo:gan>=0?'ingreso':'egreso', categoria:'Ganancia de operación', contraparteTipo:'cliente', contraparteId:c.clienteId, contraparteNombre:clienteNombre(c.clienteId), monto:Math.abs(gan), moneda:'CLP', descripcion:'Ganancia operación '+c.folio, conciliado:false });
  guardarMovimientos(); guardarConfigData(); actualizarDashboard();
  alert('Ganancia de '+c.folio+' registrada en el libro de caja ('+fmtNum(gan,0)+' CLP).');
}
function renderMovimientos(){
  const el=document.getElementById('movimientos-list'); if(!el) return;
  const q=v('mv-search').toLowerCase(), ft=v('mv-fil-tipo'), fcp=v('mv-fil-cp'), fm=v('mv-fil-mes'), fc=v('mv-fil-conc');
  let lista=movimientos;
  if(q) lista=lista.filter(m=>(m.categoria||'').toLowerCase().includes(q)||(m.contraparteNombre||'').toLowerCase().includes(q)||(m.descripcion||'').toLowerCase().includes(q));
  if(ft) lista=lista.filter(m=>m.tipo===ft);
  if(fcp) lista=lista.filter(m=>m.contraparteTipo===fcp);
  if(fm) lista=lista.filter(m=>(m.fecha||'').slice(5,7)===fm);
  if(fc) lista=lista.filter(m=>fc==='si'?m.conciliado:!m.conciliado);
  // totales por moneda
  const ing={}, egr={};
  lista.forEach(m=>{ const t=m.tipo==='ingreso'?ing:egr; t[m.moneda]=(t[m.moneda]||0)+(parseFloat(m.monto)||0); });
  const fmtTot=o=>Object.entries(o).map(([m,x])=>fmtNum(x,0)+' '+m).join(' · ')||'0';
  const neto={}; Object.entries(ing).forEach(([m,x])=>neto[m]=(neto[m]||0)+x); Object.entries(egr).forEach(([m,x])=>neto[m]=(neto[m]||0)-x);
  const ti=document.getElementById('mv-tot-ing'), te=document.getElementById('mv-tot-egr'), tn=document.getElementById('mv-tot-neto');
  if(ti) ti.textContent=fmtTot(ing); if(te) te.textContent=fmtTot(egr); if(tn) tn.textContent=fmtTot(neto);
  if(!lista.length){ el.innerHTML='<div class="empty-state"><i class="ti ti-book"></i><p>No hay movimientos registrados.</p></div>'; return; }
  el.innerHTML=lista.map(m=>{
    const ing=m.tipo==='ingreso';
    const cpTxt=m.contraparteTipo==='cliente'?'Cliente: '+esc(m.contraparteNombre||''):m.contraparteTipo==='proveedor'?'Proveedor: '+esc(m.contraparteNombre||''):'Empresa'+(m.contraparteNombre?' · '+esc(m.contraparteNombre):'');
    return '<div class="record-row"><div class="record-icon" style="background:'+(ing?'#EAF3DE':'#FCEBEB')+';"><i class="ti '+(ing?'ti-arrow-down-left':'ti-arrow-up-right')+'" style="color:'+(ing?'#27500A':'#A32D2D')+';"></i></div>'+
      '<div class="record-info"><h3>'+esc(m.categoria||(ing?'Ingreso':'Egreso'))+' · <strong style="color:'+(ing?'#27500A':'#A32D2D')+';">'+(ing?'+':'−')+fmtNum(m.monto,0)+' '+esc(m.moneda)+'</strong></h3>'+
      '<div class="record-detail">'+cpTxt+(m.descripcion?' · '+esc(m.descripcion):'')+'</div>'+
      '<div class="record-meta"><span class="badge badge-amber">'+esc(m.folio)+'</span> · '+esc(m.fecha)+' · '+(m.conciliado?'<span class="status-pill pill-verde"><span class="status-dot status-verde"></span>conciliado</span>':'<span class="status-pill pill-amarillo"><span class="status-dot status-amarillo"></span>sin conciliar</span>')+'</div>'+
      '</div><div class="record-actions">'+
      '<button class="btn btn-secondary btn-sm" onclick="toggleConciliado(\''+m.id+'\')" title="Marcar conciliado">'+(m.conciliado?'<i class="ti ti-circle-check"></i>':'<i class="ti ti-circle"></i>')+'</button>'+
      '<button class="btn btn-danger btn-sm" onclick="eliminarMovimiento(\''+m.id+'\')" title="Eliminar"><i class="ti ti-trash"></i></button>'+
      '</div></div>';
  }).join('');
}


