function saldoCuentaCliente(clienteId, moneda){ return cuenta.filter(m=>m.clienteId===clienteId && m.moneda===moneda).reduce((s,m)=>s+signoCuenta(m)*(parseFloat(m.monto)||0),0); }
function saldosCuentaCliente(clienteId){ const o={}; cuenta.filter(m=>m.clienteId===clienteId).forEach(m=>{ o[m.moneda]=(o[m.moneda]||0)+signoCuenta(m)*(parseFloat(m.monto)||0); }); return o; }
