// ═══════════════ CONCILIACIÓN BANCARIA ═══════════════
let cartolaLineas = [];
let cartolaRowsTmp = [];
function guardarCartola(){ try{ localStorage.setItem('alun_cartola', JSON.stringify(cartolaLineas)); }catch(e){} }
function padN(n){ return String(n).padStart(2,'0'); }

function parseCSV(text){
  const lines=text.split(/\r?\n/).filter(l=>l.trim()!=='');
  if(!lines.length) return [];
  const delim = (lines[0].split(';').length > lines[0].split(',').length) ? ';' : ',';
  return lines.map(line=>{
    const cells=[]; let cur='', inq=false;
    for(let i=0;i<line.length;i++){ const ch=line[i];
      if(ch==='"'){ inq=!inq; }
      else if(ch===delim && !inq){ cells.push(cur); cur=''; }
      else cur+=ch; }
    cells.push(cur);
    return cells.map(c=>c.trim().replace(/^"|"$/g,''));
  });
}
function parseMontoCartola(s){
  if(s===undefined||s===null) return 0;
  s=String(s).replace(/[^0-9.,\-]/g,'');
  if(s===''||s==='-') return 0;
  const lastDot=s.lastIndexOf('.'), lastComma=s.lastIndexOf(',');
  if(lastDot>=0 && lastComma>=0){
    if(lastComma>lastDot) s=s.replace(/\./g,'').replace(',','.');
    else s=s.replace(/,/g,'');
  } else if(lastComma>=0){
    const after=s.length-lastComma-1;
    s = (after<=2) ? s.replace(',','.') : s.replace(/,/g,'');
  } else if((s.match(/\./g)||[]).length>1){ s=s.replace(/\./g,''); }
  return parseFloat(s)||0;
}
function normFecha(s){
  s=String(s).trim(); let m;
  if(m=s.match(/^(\d{4})[-\/](\d{1,2})[-\/](\d{1,2})/)) return m[1]+'-'+padN(m[2])+'-'+padN(m[3]);
  if(m=s.match(/^(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})/)) return m[3]+'-'+padN(m[2])+'-'+padN(m[1]);
  if(m=s.match(/^(\d{1,2})[-\/](\d{1,2})[-\/](\d{2})$/)) return '20'+m[3]+'-'+padN(m[2])+'-'+padN(m[1]);
  return s;
}
function diasEntre(a,b){ const d1=new Date(a+'T00:00:00'), d2=new Date(b+'T00:00:00'); if(isNaN(d1)||isNaN(d2)) return 999; return Math.abs((d2-d1)/86400000); }

function poblarConcCuenta(){ const s=document.getElementById('conc-cuenta'); if(s){ const p=s.value; s.innerHTML='<option value="">— Sin especificar —</option>'+cuentasBancarias.map(cb=>'<option value="'+cb.id+'">'+esc(etiquetaCB(cb))+'</option>').join(''); s.value=p; } }

function leerCartolaPegada(){ const t=v('conc-paste'); if(!t.trim()){ alert('Pegue el contenido de la cartola, o use el archivo CSV.'); return; } procesarTextoCartola(t); }
function procesarTextoCartola(text){ cartolaRowsTmp=parseCSV(text); if(!cartolaRowsTmp.length){ alert('No se pudo leer contenido de la cartola.'); return; } mostrarMapeo(); }
function mostrarMapeo(){
  const panel=document.getElementById('conc-mapeo'); if(!panel) return; panel.style.display='block';
  const headerOn=document.getElementById('conc-header').checked;
  const headers=cartolaRowsTmp[0]||[];
  const ncol=Math.max(...cartolaRowsTmp.map(r=>r.length));
  let opts=''; for(let i=0;i<ncol;i++){ const lbl=headerOn&&headers[i]?headers[i]:('Columna '+(i+1)); opts+='<option value="'+i+'">'+esc(lbl)+'</option>'; }
  ['conc-col-fecha','conc-col-desc','conc-col-monto','conc-col-cargo','conc-col-abono'].forEach(id=>{ const s=document.getElementById(id); if(s) s.innerHTML=opts; });
  if(headerOn){ guessCol('conc-col-fecha',headers,['fecha','date']); guessCol('conc-col-desc',headers,['desc','glosa','detalle','movimiento','concepto']); guessCol('conc-col-monto',headers,['monto','importe','valor']); guessCol('conc-col-cargo',headers,['cargo','debito','débito','giro']); guessCol('conc-col-abono',headers,['abono','credito','crédito','deposito','depósito']); }
  onModoMonto(); renderPreviewCartola();
}
function guessCol(selId,headers,keys){ const s=document.getElementById(selId); if(!s) return; for(let i=0;i<headers.length;i++){ const h=(headers[i]||'').toLowerCase(); if(keys.some(k=>h.includes(k))){ s.value=i; return; } } }
function onModoMonto(){ const dos=v('conc-modo-monto')==='dos'; document.querySelectorAll('.conc-uno').forEach(e=>e.style.display=dos?'none':'flex'); document.querySelectorAll('.conc-dos').forEach(e=>e.style.display=dos?'flex':'none'); }
function renderPreviewCartola(){
  const el=document.getElementById('conc-preview'); if(!el) return;
  const headerOn=document.getElementById('conc-header').checked;
  const rows=cartolaRowsTmp.slice(0, headerOn?4:3);
  el.innerHTML='<table style="border-collapse:collapse;min-width:100%;"><tbody>'+rows.map((r,ri)=>'<tr>'+r.map(c=>'<td style="border:0.5px solid var(--border);padding:3px 6px;'+(headerOn&&ri===0?'font-weight:600;background:var(--bg);':'')+'">'+esc(c)+'</td>').join('')+'</tr>').join('')+'</tbody></table>';
}
function procesarCartola(){
  const bancoId=v('conc-cuenta'); const headerOn=document.getElementById('conc-header').checked;
  const start=headerOn?1:0;
  const cf=parseInt(v('conc-col-fecha')), cd=parseInt(v('conc-col-desc')), modo=v('conc-modo-monto');
  const cm=parseInt(v('conc-col-monto')), cc=parseInt(v('conc-col-cargo')), ca=parseInt(v('conc-col-abono'));
  let added=0;
  for(let i=start;i<cartolaRowsTmp.length;i++){ const row=cartolaRowsTmp[i]; if(!row||!row.length) continue;
    let monto=0;
    if(modo==='dos'){ const cargo=Math.abs(parseMontoCartola(row[cc]||'')), abono=Math.abs(parseMontoCartola(row[ca]||'')); if(abono>0) monto=abono; else if(cargo>0) monto=-cargo; else continue; }
    else { monto=parseMontoCartola(row[cm]||''); if(monto===0) continue; }
    const fecha=normFecha(row[cf]||'');
    cartolaLineas.unshift({ id:'ct'+Date.now()+'_'+i, bancoCuentaId:bancoId||null, fecha:fecha, descripcion:(row[cd]||'').slice(0,140), monto:monto, conciliado:false, matchOrigen:null, matchId:null });
    added++;
  }
  guardarCartola();
  document.getElementById('conc-mapeo').style.display='none';
  const pa=document.getElementById('conc-paste'); if(pa) pa.value=''; cartolaRowsTmp=[];
  document.getElementById('conc-fil').value='pend'; renderCartola();
  alert(added+' línea(s) importada(s). Revise las coincidencias sugeridas y confirme cada conciliación.');
}

function itemsConciliables(){
  const arr=[];
  movimientos.forEach(m=>{ if(!m.conciliado) arr.push({origen:'libro', id:m.id, fecha:m.fecha, signo:m.tipo==='ingreso'?1:-1, monto:parseFloat(m.monto)||0, desc:(m.categoria||'')+(m.contraparteNombre?' · '+m.contraparteNombre:''), moneda:m.moneda}); });
  cuenta.forEach(m=>{ if((m.tipo==='deposito'||m.tipo==='retiro') && !m.conciliado) arr.push({origen:'cuenta', id:m.id, fecha:m.fecha, signo:m.tipo==='deposito'?1:-1, monto:parseFloat(m.monto)||0, desc:'Cuenta · '+clienteNombre(m.clienteId), moneda:m.moneda}); });
  return arr;
}
function buscarMatch(linea){
  const signo=linea.monto>=0?1:-1, abs=Math.abs(linea.monto);
  const items=itemsConciliables().filter(it=>it.signo===signo && Math.abs(it.monto-abs)<0.5);
  let best=null, bestDiff=Infinity;
  items.forEach(it=>{ const d=diasEntre(it.fecha, linea.fecha); if(d<=7 && d<bestDiff){ best=it; bestDiff=d; } });
  return best;
}
function marcarItemConciliado(origen,id,val){
  if(origen==='libro'){ const m=movimientos.find(x=>x.id===id); if(m){ m.conciliado=val; guardarMovimientos(); } }
  else if(origen==='cuenta'){ const m=cuenta.find(x=>x.id===id); if(m){ m.conciliado=val; guardarCuenta(); } }
}
function conciliarLinea(lineId, origen, itemId){
  const line=cartolaLineas.find(l=>l.id===lineId); if(!line) return;
  marcarItemConciliado(origen,itemId,true);
  line.conciliado=true; line.matchOrigen=origen; line.matchId=itemId;
  guardarCartola(); renderCartola();
}
function crearMovDesdeLinea(lineId){
  const line=cartolaLineas.find(l=>l.id===lineId); if(!line) return;
  const cb=cuentaBancariaPorId(line.bancoCuentaId); const mon=cb?cb.moneda:'CLP';
  const tipo=line.monto>=0?'ingreso':'egreso';
  const m={ id:'mv'+Date.now(), folio:nuevoFolioMov(), creadoEn:new Date().toISOString(), fecha:line.fecha||hoy(), tipo:tipo, categoria:'Cartola bancaria', contraparteTipo:'empresa', contraparteId:null, contraparteNombre:line.descripcion, monto:Math.abs(line.monto), moneda:mon, descripcion:line.descripcion, conciliado:true };
  movimientos.unshift(m); guardarMovimientos(); guardarConfigData();
  line.conciliado=true; line.matchOrigen='libro'; line.matchId=m.id;
  guardarCartola(); renderCartola(); renderMovimientos();
}
function desconciliarLinea(lineId){
  const line=cartolaLineas.find(l=>l.id===lineId); if(!line) return;
  if(line.matchOrigen&&line.matchId) marcarItemConciliado(line.matchOrigen,line.matchId,false);
  line.conciliado=false; line.matchOrigen=null; line.matchId=null;
  guardarCartola(); renderCartola();
}
function quitarLineaCartola(lineId){ if(!confirm('¿Quitar esta línea de la cartola?')) return; const l=cartolaLineas.find(x=>x.id===lineId); if(l&&l.conciliado&&l.matchOrigen) marcarItemConciliado(l.matchOrigen,l.matchId,false); cartolaLineas=cartolaLineas.filter(x=>x.id!==lineId); guardarCartola(); renderCartola(); }
function limpiarCartola(){ if(!cartolaLineas.length) return; if(!confirm('¿Vaciar todas las líneas de cartola importadas? (los movimientos del sistema no se borran)')) return; cartolaLineas.forEach(l=>{ if(l.conciliado&&l.matchOrigen) marcarItemConciliado(l.matchOrigen,l.matchId,false); }); cartolaLineas=[]; guardarCartola(); renderCartola(); }

function renderCartola(){
  const el=document.getElementById('cartola-list'); if(!el) return;
  const ok=cartolaLineas.filter(l=>l.conciliado).length, pend=cartolaLineas.length-ok;
  const so=document.getElementById('conc-tot-ok'), sp=document.getElementById('conc-tot-pend'), sa=document.getElementById('conc-tot-all');
  if(so) so.textContent=ok; if(sp) sp.textContent=pend; if(sa) sa.textContent=cartolaLineas.length;
  const fil=v('conc-fil');
  let lista=cartolaLineas;
  if(fil==='pend') lista=lista.filter(l=>!l.conciliado); else if(fil==='ok') lista=lista.filter(l=>l.conciliado);
  if(!lista.length){ el.innerHTML='<div class="empty-state"><i class="ti ti-file-check"></i><p>'+(cartolaLineas.length?'No hay líneas en este filtro.':'Importe una cartola para comenzar a conciliar.')+'</p></div>'; return; }
  el.innerHTML=lista.map(l=>{
    const ing=l.monto>=0;
    const montoTxt='<strong style="color:'+(ing?'#27500A':'#A32D2D')+';">'+(ing?'+':'−')+fmtNum(Math.abs(l.monto),0)+'</strong>';
    let accion='';
    if(l.conciliado){
      accion='<span class="status-pill pill-verde"><span class="status-dot status-verde"></span>conciliada</span> <button class="btn btn-secondary btn-sm" onclick="desconciliarLinea(\''+l.id+'\')"><i class="ti ti-arrow-back-up"></i> Deshacer</button>';
    } else {
      const m=buscarMatch(l);
      if(m){ accion='<div style="font-size:12px;color:var(--text-muted);margin-bottom:6px;">Coincidencia sugerida: <strong>'+esc(m.desc)+'</strong> ('+esc(m.fecha)+')</div><button class="btn btn-primary btn-sm" onclick="conciliarLinea(\''+l.id+'\',\''+m.origen+'\',\''+m.id+'\')"><i class="ti ti-check"></i> Conciliar</button> <button class="btn btn-secondary btn-sm" onclick="crearMovDesdeLinea(\''+l.id+'\')"><i class="ti ti-plus"></i> Crear movimiento</button>'; }
      else { accion='<div style="font-size:12px;color:#A32D2D;margin-bottom:6px;">Sin coincidencia en el sistema.</div><button class="btn btn-primary btn-sm" onclick="crearMovDesdeLinea(\''+l.id+'\')"><i class="ti ti-plus"></i> Crear movimiento y conciliar</button>'; }
    }
    return '<div class="record-row"><div class="record-icon" style="background:'+(ing?'#EAF3DE':'#FCEBEB')+';"><i class="ti '+(ing?'ti-arrow-down-left':'ti-arrow-up-right')+'" style="color:'+(ing?'#27500A':'#A32D2D')+';"></i></div>'+
      '<div class="record-info"><h3>'+esc(l.fecha)+' · '+montoTxt+'</h3>'+
      '<div class="record-detail">'+esc(l.descripcion||'(sin descripción)')+'</div>'+
      '<div class="record-meta" style="margin-top:6px;">'+accion+'</div>'+
      '</div><div class="record-actions"><button class="btn btn-danger btn-sm" onclick="quitarLineaCartola(\''+l.id+'\')" title="Quitar línea"><i class="ti ti-x"></i></button></div></div>';
  }).join('');
}


function init(){
  registros=cargar('alun_registros',[]);
  clientes=cargar('alun_clientes',[]);
  facturas=cargar('alun_facturas',[]);
  compras=cargar('alun_compras',[]);
  movimientos=cargar('alun_movimientos',[]);
  proveedores=cargar('alun_proveedores',[]);
  cuenta=cargar('alun_cuenta',[]);
  cuentasBancarias=cargar('alun_cuentas_bancarias',[]);
  cartolaLineas=cargar('alun_cartola',[]);
  const c=cargar('alun_config',null); if(c){ config=Object.assign(config,c); if(!config.logo) config.logo=LOGO_ALUN; }
  migrar();
  aplicarLogo(); attachFileInputs();
  setTipoPersona('juridica'); setFacturaModo('individual'); togglePep();
  renderBeneficiarios(); renderDestinatarios(); renderDocCliente();
  renderComprobante(); renderFactura(); renderOtros(); renderNF();
  document.getElementById('tx-fecha').value=hoy();
  cargarConfigForm(); poblarSelectsCompra(); setTipoOperacion('compra_div'); renderCompras(); renderSaldos(); poblarMovCliente(); onMovContraparte(); const mvf=document.getElementById('mv-fecha'); if(mvf) mvf.value=hoy(); renderMovimientos(); const cof=document.getElementById('co-fecha'); if(cof) cof.value=hoy(); actualizarDashboard(); verificarAlertas(); verificarPendientes();
  document.getElementById('modal-overlay').addEventListener('click',function(e){ if(e.target===this) cerrarModal(); });
}
init();

